var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"이곳이 페리어가 자주 찾는다는 찻집이군요.","JPN":"この喫茶店が、フェリエーのお気に入りなんですね。","ENG":"So this is the tea house that you frequent.","TWN":"這裡就是佩里常來的茶館啊。"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RYAN_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L4_1","type":"dialog","speaker":"RYAN_PRYDWEN_NULL_NULL","text":{"KOREA":"그렇습니다. 좋은 찻잎과 아늑한 분위기를 갖춘 숨겨진 명소죠.","JPN":"はい。いい茶葉と穏やかな雰囲気を兼ね備えた隠れ家です。","ENG":"That's right. It's a hidden gem, with the finest tea leaves and a cozy atmosphere.","TWN":"是的。茶葉好，環境雅致，是個不為人所知的好地方。"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RYAN_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L5_1","type":"dialog","speaker":"RYAN_PRYDWEN_NULL_NULL","text":{"KOREA":"아가씨께서도 마음에 들어하실 것이라고 자부합니다.","JPN":"きっと、お嬢様もお気に召すはずです。","ENG":"I'm confident that you'll find it to your liking as well.","TWN":"我敢保證，小姐您也一定會喜歡的。"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RYAN_PRYDWEN_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L6_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"잘됐네요. 물벼룩을 기관에 들인 뒤로 한동안 쉬지 못했죠.","JPN":"ちょうどいいですわ。ミジンコが機関に入って以来、ろくに休んでいないので。","ENG":"That's good to hear. I've hardly had a break ever since we took in the Water Flea.","TWN":"正好，自從水蚤進入機關後，我就有很長的時間沒有好好休息了。"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RYAN_PRYDWEN_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L7_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"음......?","JPN":"……うん？","ENG":"Huh?","TWN":"嗯……？"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RYAN_PRYDWEN_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"힉?!","JPN":"ひっ！？","ENG":"Eep?!","TWN":"噫？！"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"STAFF_NPC_NULL_NULL","text":{"KOREA":"왜 그러시죠, 손님? 홍차가 마음에 안 드시나요?","JPN":"お客様、どうされましたか？　紅茶に何か問題でも？","ENG":"What's wrong, ma'am? Is the tea not to your liking?","TWN":"怎麼了，客人？您對紅茶不滿意嗎？"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"아, 아뇨! 무척 마음에 들어요! 그런데 제가 뭘 하고 있었죠?!","JPN":"い、いいえ！　とても素晴らしい紅茶ですわ！　ところで今、私は何をしてましたの？","ENG":"N-no! It's very nice! But what was I doing just now?","TWN":"啊，不是！我非常滿意！不過我剛剛在做什麼呢？！"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"STAFF_NPC_NULL_NULL","text":{"KOREA":"방금까지 차를 마시면서 독서 중이셨습니다만......","JPN":"先ほどまで、お茶を楽しみながら読書をなさってましたが……","ENG":"You were reading and drinking tea...","TWN":"直到剛才，您都在一邊喝茶，一邊看書……"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"그, 그랬죠! 갑자기 급한 용무가 생겨서 그러는데 남은 차는 포장해 주세요!","JPN":"そ、そうでしたわ！　急な用事を思い出したので、残りの紅茶は持ち帰りますわね！","ENG":"O-oh, right! Sorry, but I've got an urgent matter to attend to. I'll take the rest in a doggy bag please!","TWN":"對、沒錯！我突然有急事，請將剩下的茶葉幫我打包起來！"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"STAFF_NPC_NULL_NULL","text":{"KOREA":"손님...... 한 번 우린 티백은 포장해 드리기가 곤란합니다.","JPN":"お客様……一度お茶を淹れたティーバッグはお包みできません。","ENG":"Ma'am... We can't exactly put a tea bag in a doggy bag once it's been brewed...","TWN":"客人……泡過一次的茶包是不能打包的。"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"기껏 좋은 가게에 와서 CTC 제법으로 만든 찻잎을 고르다니, 홍차에는 문외한이네요.","JPN":"せっかく素敵なお店に来たのに、CTC製法の茶葉を選ぶなんて。\\n紅茶に関しては、素人同然ですわね。","ENG":"You come to a posh establishment like this and choose a CTC tea? You're clueless about tea, aren't you?","TWN":"難得到了一家這麼好的店裡，居然選了CTC製法做成的茶葉。看來在紅茶方面，妳是個外行人呢。"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"또 잘난 척이네요! 무슨 찻잎을 고를지는 제 취향이죠!","JPN":"また偉そうに！　どんな茶葉を選ぼうと、私の勝手ですわ！","ENG":"There you go again, bragging like a snob! I've got every right to pick the tea I like!","TWN":"又一副跩樣！選什麼茶葉是我的自由！"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"......저, 그런데 CTC가 무슨 뜻이에요?","JPN":"……あの、ところでCTCって何ですの？","ENG":"Uh, by the way... What does CTC stand for?","TWN":"……呃，不過，那個CTC是什麼意思？"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"부수고, 찢고, 비빈다는 말의 약자랍니다. 품질이 제각각인 찻잎으로 적당한 수준의 맛을 낼 때 쓰이죠.","JPN":"Crush＝つぶす/Tear＝裂く/Curl＝丸めるの略です。\\n品質がまばらな茶葉で、ほどほどの味を作り出す際に使われます。","ENG":"It stands for crush, tear, and curl. It's a process used to package tea leaves of inconsistent quality.","TWN":"是碾碎、撕開、揉搓意思的縮寫。是品質參差不齊的茶葉所混合，味道等級一般的茶。"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"다시 말해, 이런 전문점이 아니라도 어디서나 구할 수 있는 공산품이란 뜻이에요.","JPN":"簡単に言えば、このような専門店じゃなくても手に入る、大量生産による商品です。","ENG":"In other words, it's a mass-produced product you can find anywhere without having to visit a dedicated tea house like this.","TWN":"換句話說，就算不來這種專門店，隨便在哪裡都能喝到的工業製品，。"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"맥크레디 양이라면 보나마나 점원에게 추천 받는 대신 자기 눈에 띄는 걸 고르고 봤겠죠.","JPN":"マクレディーさんなら、店員さんにおすすめを聞く代わりに、自分で選んだのでしょう。","ENG":"It's likely you simply picked out what you were familiar with instead of asking the staff for recommendations, Ms. MacCready.","TWN":"麥克雷迪小姐的話，比起店員為妳推薦，是自己選了個顯眼的東西吧。"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"그, 그걸 어떻게......","JPN":"ど、どうしてそれを……","ENG":"H-how did you know...","TWN":"妳、妳怎麼會……"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"아니. 죄송하지만 사람 잘못 보셨어요. 전 맥크레디가 아니에요.","JPN":"い、いいえ。失礼ですが人違いです。私は、マクレディーではありませんわ。","ENG":"Hang on. Sorry, but you've got the wrong person. I'm not MacCready.","TWN":"不，很抱歉，妳認錯人了，我不是麥克雷迪。"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"그래요? 레지나 맥크레디가 아니면 당신은 누구죠?","JPN":"そうですか？　レジーナ・マクレディーでなければ、何者でしょうか？","ENG":"Really? Then who might you be, if you're not Regina\xA0MacCready?","TWN":"是嗎？妳不是里賈納·麥克雷迪的話，那妳會是誰？"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L30_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"그게, 맥...... 도날드입니다. 레지나 맥도날드.","JPN":"その、マク……ドナルドです。レジーナ・マクドナルド。","ENG":"Well, I'm... Mac... Donald. Regina MacDonald.","TWN":"那個，是麥……當勞，里賈納·麥當勞。"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L31_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L32_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"뭐, 뭐예요! 그 사람 안쓰럽게 보는 눈빛은!","JPN":"な、何ですか！　その哀れむような目つきは！","ENG":"W-what! Why are you looking at me with such pity in your eyes?!","TWN":"幹、幹嘛啦！幹嘛用那種憐憫的眼神看我！"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L33_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"어쨌거나 전 주문해 놓은 찻잎을 사서 돌아가야겠어요. 만나서 반가웠습니다.","JPN":"とにかく私は、注文しておいた茶葉を買って帰りますわ。ごきげんよう。","ENG":"Anyway, I'd better head back with the tea I've ordered. It was nice to meet you.","TWN":"總之，我拿了點好的茶葉後就得回去了。很高興見到妳。"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L35_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"주문해 놓았다는 찻잎도 CTC 제법으로 만든 것 아닌가요?","JPN":"その茶葉もCTC製法で作ったものでしょう？","ENG":"Isn't the tea you've ordered also a CTC tea?","TWN":"妳點的茶葉是不是也是CTC製法製成的？"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"윽......","JPN":"うっ……","ENG":"Ugh...","TWN":"唔……"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"그렇게 전전긍긍하지 마세요, 맥도날드 양. 전 오늘 휴식을 즐기러 왔답니다.","JPN":"落ち着いてください、マクドナルドさん。私はゆっくり休むために、この店を訪れたので。","ENG":"There's really no need for such trepidation, Miss... MacDonald. I'm simply here to relax today.","TWN":"別這麼戰戰兢兢的，麥當勞小姐。我今天是來享受休閒時光的。"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"그리고...... 당신의 힘은 제어를 잃으면 꽤 골치 아파지거든요.","JPN":"それに……あなたの力は、コントロールが利かなくなると大変面倒なんです。","ENG":"Besides... Your ability can be quite a nuisance if it gets out of control.","TWN":"而且……妳的力量一旦失控，可是會讓人相當頭痛呢。"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"시내가 통째로 얼음덩이가 되는 광경은 감상하고 싶지 않네요.","JPN":"街が氷に包まれる光景は見たくありませんわ。","ENG":"I'd rather not watch the entire downtown freeze over today.","TWN":"我可不想看到整個市區都被凍成一個大冰塊。"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"......저도 천박하게 진흙탕 싸움을 벌이긴 싫습니다.","JPN":"……私も品のないケンカはお断りですわ。","ENG":"I'm not looking for a messy fight either.","TWN":"……我也不喜歡沒有格調地亂打一通。"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"하지만 이전번에도 갑자기 들이닥친 불청객들 때문에 곤혹을 치른 적이 있어서 말이죠.","JPN":"しかし、この間も招かれざる客が突然やってきて、とても困りましたの。","ENG":"It's just that I ran into some trouble with unwelcome guests before as well.","TWN":"不過，上次也因為突然殺出來的不速之客，讓我碰到不少麻煩呢。"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"글쎄요, 집안 내력 때문 아닐까요?","JPN":"さあ、家柄のせいじゃないですか？","ENG":"Perhaps it's your family history that should be blamed.","TWN":"這個嘛，是出自妳們家族的歷史吧？"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"물론 맥도날드 양이 앞으로 잘 해 나간다면 그런 불상사도 줄어들겠죠. 부질없는 기대라고 생각하지만요.","JPN":"もちろんこの先、マクドナルドさんがしっかりしてくだされば、そのようなこともなくなるはずです。\\n大して期待はしてませんが。","ENG":"I'm sure such inconvenience could become less frequent for your family under your leadership. Although I suppose it may be only a pipe dream for now.","TWN":"當然，要是麥當勞小姐以後做得好，那樣的不幸應該也會減少吧，雖然我並不期待就是了。"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"......당신도 참 사람 기분 나쁘게 말할 줄 아네요.","JPN":"……本当に嫌味な人ですわね。","ENG":"You really know how to push people's buttons, don't you?","TWN":"……妳說話可說得真難聽啊。"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"솔직할 뿐이죠.","JPN":"正直なだけですわ。","ENG":"I'm only being honest.","TWN":"只是很坦率而已。"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"그보다 마침 당신에게 알맞은 홍차가 있군요. 시작은 이걸로 해 보세요.","JPN":"それより、あなたにピッタリの紅茶があります。初心者にお勧めですよ。","ENG":"By the way, I see a tea that would be perfect for you. Why don't you start with this instead?","TWN":"不說這個了，這裡正好有一款適合妳的紅茶呢。妳就從這款茶葉開始吧。"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L47_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"오? 뭐 하고 있어, 레지나?","JPN":"あれ？　何してるの、レジーナ？","ENG":"Huh? What are you doing here, Regina?","TWN":"哦？妳在幹什麼，里賈納？"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"티타임을 즐기는 중이에요. 한 가문의 주인이 되었으니 그에 걸맞은 교양을 쌓아야죠.","JPN":"ティータイムを楽しんでいます。一族の主になったので、それ相応の教養が必要でしょう？","ENG":"Enjoying my afternoon tea. I ought to foster the level of elegance expected of a leader of a household.","TWN":"我正在享受下午茶。我已經是一個家族的主人了，自然要有與之相配的素養才行。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"또 에델이 이상한 바람 넣었나 보네. 이 팔랑귀 같으니라구.","JPN":"またエデルが変なこと言ったの？　ホントに影響されやすいんだから。","ENG":"Edel's been talking that nonsense to you again, huh? You're so easy to sway.","TWN":"看來埃德爾又說了什麼奇怪的話了，妳也真是會被他人牽著走耶。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L5_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"근데 그 홍차, 직접 끓인 거야? 나 한 번 마셔 봐도 돼?","JPN":"ところでその紅茶、自分で淹れたの？　飲んでみていい？","ENG":"By the way, did you make the tea yourself? Can I try a sip?","TWN":"不過這個紅茶，是妳泡的嗎？我能嘗嘗看嗎？"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"얼마든지요.","JPN":"どうぞ。","ENG":"Of course.","TWN":"妳想喝就喝吧。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"하지만 당신처럼 점잖지 못한 사람이 즐길 수 있을지는 모르겠네요.","JPN":"でも、あなたのように品性に欠ける人の口に合うかしら。","ENG":"But I'm not sure if someone unrefined like you could enjoy something like this.","TWN":"但不知道像你這種不斯文的人，有沒有辦法享受就是了。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"헤헷. 그냥 과자랑 맛있게 먹으면 그만이지.","JPN":"へへっ。お菓子と一緒に、おいしく飲めれば十分じゃない？","ENG":"Heh. I'm sure it'll taste just fine with the biscuits and cream.","TWN":"嘿嘿，搭配餅乾一起吃就行了。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"점잖고 말고가 무슨 상관이야......","JPN":"品性なんて、別に関係ない……","ENG":"You don't have to be sophisticated to enjoy something like—","TWN":"跟斯文不斯文有什麼關係……"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":" 푸웁퉷!!","JPN":"ブフッ！？","ENG":" Blech!","TWN":"噗噗呸！！"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L11_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"무슨 홍차가 이렇게 써! 혓바닥이 얼얼하잖아?!","JPN":"なんでこんなに苦いのよ！　舌がピリピリする！","ENG":"Why's it so bitter?! My tongue is all numb!","TWN":"什麼紅茶這麼苦！舌頭都麻掉了耶？！"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L12_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"후훗. 팬드래건 양이 직접 골라 준 찻잎이에요.","JPN":"ふふっ、ペンドラゴンさんが直接選んでくれた茶葉ですわ。","ENG":"Heh heh. Ms. Pendragon picked it out for me herself.","TWN":"呵呵，這是潘德拉貢小姐親自幫我挑選的茶葉。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L13_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"이...... 이 정도 쓴맛은 대범하게 넘길 수 있어야 귀족답다는 뜻이겠죠!","JPN":"こ……このような苦みに慣れ親しんでこそ、本物の貴族と言えるのですわ！","ENG":"I... I'm sure a true noblewoman's supposed to endure such bitterness for the sake of sophistication!","TWN":"想來這是……能夠雍容大度地品嘗這種苦澀，才能像個貴族的意思！"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L14_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"......암만 봐도 그냥 놀려 먹은 거잖아, 이 푼수야.","JPN":"……どうみても、からかわれただけじゃん。バカだなぁ。","ENG":"She's obviously messing around with you, you twit.","TWN":"……怎麼看都覺得她是在捉弄妳啦，妳這個笨蛋。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_DESPAIR"}}}}]`);export{e as default};